class Solution {
    public int kIncreasing(int[] arr, int k) {
        int n = arr.length;
        int[] prefix = new int[n];
        int[] suffix = new int[n];
        int operations = 0;

        for (int i = 0; i < n; i++) {
            if (i >= k) {
                prefix[i] = Math.max(prefix[i - k], arr[i]);
            } else {
                prefix[i] = arr[i];
            }
        }

        for (int i = n - 1; i >= 0; i--) {
            if (i < n - k) {
                suffix[i] = Math.max(suffix[i + k], arr[i]);
            } else {
                suffix[i] = arr[i];
            }
        }

        for (int i = 0; i < n; i++) {
            if (i >= k) {
                operations += Math.max(0, arr[i] - prefix[i - k]);
            }
            if (i < n - k) {
                operations += Math.max(0, suffix[i + k] - arr[i]);
            }
        }

        return operations;
    }
}
